import '../lib/event_cursor.dart';
import '../lib/inbox.dart';

void main() {
  final instant = DateTime.utc(2026, 7, 3, 14, 0);
  final inbox = EventInbox();
  inbox.applyBatch([
    LedgerEvent(id: 'first', occurredAt: instant, sequence: 1),
  ]);

  final accepted = inbox.applyBatch([
    LedgerEvent(id: 'third', occurredAt: instant, sequence: 3),
    LedgerEvent(id: 'duplicate', occurredAt: instant, sequence: 1),
    LedgerEvent(
      id: 'next-time',
      occurredAt: instant.add(const Duration(milliseconds: 1)),
      sequence: 1,
    ),
    LedgerEvent(id: 'second', occurredAt: instant, sequence: 2),
  ]);

  final ids = accepted.map((event) => event.id).join(',');
  if (ids != 'second,third,next-time') {
    throw StateError('unexpected cross-batch order: $ids');
  }
}
